INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-appraiser-moex-00293', 'real-estate-appraiser', 'real-estate-appraiser-moex-102-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '《史記．魏公子列傳》：「公子為人仁而下士，士無賢不肖皆謙而禮交之。」句中 「下」字是方位名詞當動詞用，下列選項「」中詞語的用法，何者與此相同？', '["子路從而「後」，遇丈人，以杖荷蓧（《論語．微子》）", "子墨衰絰，梁弘御戎，萊駒為「右」（《左傳．僖公三十三年》）", "項王乃復引兵而「東」，至東城，乃有二十八騎（《史記．項羽本記》）", "螾無爪牙之利，筋骨之強，「上」食埃土，下飲黃泉（《荀子．勸學》）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "eb9ff049f5c7", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "905", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00294', 'real-estate-appraiser', 'real-estate-appraiser-moex-102-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '樊遲從遊於舞雩之下，曰：「敢問崇德、脩慝、辨惑。」子曰：「善哉問！先事後 得，非崇德與？攻其惡，無攻人之惡，非脩慝與？一朝之忿，忘其身以及其親，非 惑與？」（《論語．顏淵》） 文中孔子認為「崇德」的基礎近於下列何者？', '["只問耕耘，不問收穫", "三省吾身，不欺暗室", "先之勞之，不憂不懼", "仁民愛物，不忮不求"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "eb9ff049f5c7", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "905", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00295', 'real-estate-appraiser', 'real-estate-appraiser-moex-102-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '趙清獻公知越州，兩浙旱蝗，米價踴貴，饑死相望。 諸州皆榜衢路，禁人增米價。公獨榜通衢，令有米者增價糶之。於是米商輻輳，米 價更賤。 根據上文，對趙清獻公最適切的論述是：', '["不能苦民所苦", "不顧百姓，圖利米商", "能逆向操作，以量制價", "能未雨綢繆，使米賤民蘇"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "eb9ff049f5c7", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "905", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00296', 'real-estate-appraiser', 'real-estate-appraiser-moex-102-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '寇萊公……歷富貴四十年，無田園邸第。入覲則寄僧舍或僦居。在大名日，自出題 試貢士，曰〈公儀休拔園葵賦〉、〈霍將軍辭治第詩〉，此其志也。詩人魏野獻詩 曰：「有官居鼎鼐，無地起樓臺。」采詩者以為中的。虜使至大名，問公曰：「莫 是『無地起樓臺』相公否？」（《湘山野錄》卷三） 根據上文，選出敘述正確的選項：', '["寇萊公應舉時所作詩賦，即已顯現清廉之志", "寇萊公清廉儉樸之名，連外國使臣都曾聽聞", "魏野的名句，外國使臣誤認為是寇萊公之作", "魏野詩譏諷寇萊公故作儉樸，頗受時人認同"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "eb9ff049f5c7", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "905", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00297', 'real-estate-appraiser', 'real-estate-appraiser-moex-102-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '曹丕〈與吳質書〉：「昔伯牙絕弦於鍾期，仲尼覆醢於子路，痛知音之難遇，傷門 人之莫逮。諸子但為未及古人，自一時之雋也。今之存者，已不逮矣！後生可畏， 來者難誣。然恐吾與足下不及見也。」 關於此段文字之敘述，下列何者正確？', '["「後生可畏，來者難誣」之「畏」引申有敬佩之意", "「伯牙絕弦於鍾期」的原因是從此無人可以調音，無法再演奏", "「仲尼覆醢於子路」敘述孔子因子路衝動、魯莽，而不願與之共餐", "「然恐吾與足下不及見也」，在感嘆後生晚輩實力無法預測，令人擔憂"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "eb9ff049f5c7", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "905", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00298', 'real-estate-appraiser', 'real-estate-appraiser-moex-102-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '高子病痿，不出內戶者旬月。客散擁榻，目無所寄，則常屬之窗與簾。簾附窗，而 嫟於壁，壁之穴蟲多緣而遊。有蛛初來登簾，若涉大險。簾有界隙，動輒失足，失 足則驚，驚輒退縮不敢前，則惴惴而行，帖帖而蹲，其勢若不終日者已。乃戲令撤 其窗扉，使去壁遠而絕其歸，奪其所安而重困之。意初不堪，久且苦飢，無所食， 則強起而掠簾蠅。一日而坦，二日而躍，三日則投擲如飛矣。 下列文句最接近本文意旨的選項是：', '["置之死地而後生", "業精於勤荒於嬉", "立身行己，居安如墜", "怨人不如自怨，求諸人不如求諸己"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "eb9ff049f5c7", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "905", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00299', 'real-estate-appraiser', 'real-estate-appraiser-moex-102-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '白居易〈杏園中棗樹〉：「人言百果中，唯棗凡且鄙。皮皴似龜手，葉小如鼠耳。 胡為不自知，生花此園裏。……東風不擇木，吹煦長未已。眼看欲合抱，得盡生生 理。寄言遊春客，乞君一迴視。君愛繞指柔，從君憐柳杞。君求悅目豔，不敢爭桃 李。君若作大車，輪軸材須此。」 下列選項，何者最切近本文旨意？', '["強調女為悅己者容", "強調賞心悅目的重要", "強調為人必須表裏一致", "強調物雖或平凡，卻能致用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "eb9ff049f5c7", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "905", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00300', 'real-estate-appraiser', 'real-estate-appraiser-moex-102-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '王守仁〈教條示龍場諸生〉：「責善，朋友之道。然須忠告而善道之，悉其忠愛，致 其婉曲，使彼聞之而可從，繹之而可改，有所感而無所怒，乃為善耳。若先暴白其過 惡，痛毀極詆，使無所容，彼將發其愧恥憤恨之心，雖欲降以相從，而勢有所不能。」 根據上文，下列敘述何者正確？', '["「暴白其過惡，痛毀極詆」有助於責善", "激起朋友的「愧恥憤恨之心」是責善的目的", "「繹之而可改」是有心向善的人難以做到的", "「悉其忠愛，致其婉曲」是理想的責善之道"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "eb9ff049f5c7", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "905", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00301', 'real-estate-appraiser', 'real-estate-appraiser-moex-102-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '「不畏浮雲遮望眼」（王安石〈登飛來峰〉），是對待政治現實的態度。下列詩文 中「浮雲」此一意象所指涉的意義，何者與本句中的「浮雲」相同？', '["雷鼓震地起，猛勢陵浮雲（《宋書．樂志》）", "不義而富且貴，於我如浮雲（《論語．述而》）", "總為浮雲能蔽日，長安不見使人愁（李白〈登金陵鳳凰臺〉）", "從前種種暱愛，如浮雲散滅，都無餘滓（《閱微草堂筆記．灤陽消夏錄》） 孟嘗君逐於齊而復反。譚拾子迎之於境，謂孟嘗君曰：「君得無有所怨齊士大夫？」孟 嘗君曰：「有。」「君滿意殺之乎？」孟嘗君曰：「然。」譚拾子曰：「事有必至，理 有固然，君知之乎？」孟嘗君曰：「不知。」譚拾子曰：「事之必至者，死也；理之固 然者，富貴則就之，貧賤則去之。此事之必至，理之固然者。請以市諭：市，朝則滿， 夕則虛，非朝愛市而夕憎之也。求存故往，亡故去。願君勿怨。」孟嘗君乃取所怨五百 牒削去之，不敢以為言。（《戰國策．齊策》） 請依上文回答第13題至第14題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "eb9ff049f5c7", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "905", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL),
  ('real-estate-appraiser-moex-00302', 'real-estate-appraiser', 'real-estate-appraiser-moex-102-9a386a01', 'sub-real-estate-appraiser-08', NULL, 'single_choice', '文中「孟嘗君逐於齊而復反」，意謂：', '["孟嘗君奔走於齊國企圖再次謀反", "孟嘗君被齊君驅逐以後企圖謀反", "孟嘗君遭齊君罷黜以後又被召回", "孟嘗君到齊國訪求賢才後返回國境"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:05+00:00", "source_pdf_sha1": "eb9ff049f5c7", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "905", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "appraiser", "db_exam_id": "real-estate-appraiser"}'::jsonb, NULL)
